var e=[{id:`estructura-atomo`,title:`Estructura del Átomo`,category:`Química General`,duration:`8 min`,icon:`⚛️`,description:`Conoce las partículas subatómicas, el núcleo y la nube electrónica.`,steps:[{type:`text`,title:`¿Qué es un átomo?`,content:`El átomo es la unidad más pequeña de la materia que conserva las propiedades de un elemento químico. Está compuesto por un núcleo central (protones + neutrones) y una nube de electrones que orbitan alrededor.`,highlight:`El 99.9% de la masa del átomo está en el núcleo, pero ocupa solo 1/10,000 de su volumen.`},{type:`diagram`,title:`Partes del Átomo`,caption:`Helio: 2 protones, 2 neutrones, 2 electrones`,svg:`<svg viewBox="0 0 200 180" class="w-48 h-48 mx-auto"><circle cx="100" cy="80" r="60" fill="none" stroke="#0066FF" stroke-width="1" opacity="0.3"/><circle cx="100" cy="80" r="40" fill="none" stroke="#0066FF" stroke-width="1" opacity="0.2"/><circle cx="100" cy="80" r="15" fill="#FF6B6B" opacity="0.8"/><circle cx="94" cy="76" r="5" fill="#FF4444"/><circle cx="106" cy="76" r="5" fill="#FF4444"/><circle cx="100" cy="85" r="5" fill="#4A4A4A"/><circle cx="100" cy="85" r="5" fill="#4A4A4A"/><circle cx="140" cy="60" r="4" fill="#4FC3F7"/><circle cx="65" cy="110" r="4" fill="#4FC3F7"/><text x="100" y="170" text-anchor="middle" font-size="11" fill="#666">Protón (+) - Neutrón - Electrón (-)</text></svg>`},{type:`text`,title:`Partículas Subatómicas`,content:`Protón (carga +1, masa 1 u): en el núcleo. Neutrón (carga 0, masa 1 u): en el núcleo. Electrón (carga -1, masa 1/1836 u): en la nube electrónica.`},{type:`example`,title:`Ejemplo: Átomo de Carbono`,content:`El carbono (C) tiene 6 protones, 6 neutrones y 6 electrones. Número atómico Z=6, masa atómica A≈12.`},{type:`interactive`,title:`Actividad Rápida`,question:`¿Qué partícula subatómica tiene carga positiva?`,options:[`Electrón`,`Protón`,`Neutrón`,`Fotón`],correctIndex:1,explanation:`Los protones tienen carga positiva (+1) y se encuentran en el núcleo del átomo.`}]},{id:`enlaces-quimicos`,title:`Enlaces Químicos`,category:`Química General`,duration:`10 min`,icon:`🔗`,description:`Aprende cómo los átomos se unen mediante enlaces iónicos, covalentes y metálicos.`,steps:[{type:`text`,title:`¿Por qué se unen los átomos?`,content:`Los átomos se enlazan para alcanzar una configuración más estable, completando su capa de valencia (regla del octeto: 8 electrones).`},{type:`diagram`,title:`Enlace Iónico vs Covalente`,caption:`Iónico: transferencia de electrones. Covalente: compartición de electrones.`,svg:`<svg viewBox="0 0 300 120" class="w-full max-w-sm mx-auto"><text x="20" y="20" font-size="12" font-weight="bold" fill="#2563EB">Iónico</text><rect x="20" y="30" width="70" height="50" rx="8" fill="#DBEAFE" stroke="#2563EB"/><text x="55" y="58" text-anchor="middle" font-size="16" fill="#1E40AF">Na⁺</text><rect x="95" y="30" width="70" height="50" rx="8" fill="#FEE2E2" stroke="#DC2626"/><text x="130" y="58" text-anchor="middle" font-size="16" fill="#991B1B">Cl⁻</text><text x="170" y="20" font-size="12" font-weight="bold" fill="#059669">Covalente</text><circle cx="210" cy="55" r="18" fill="#D1FAE5" stroke="#059669"/><circle cx="260" cy="55" r="18" fill="#D1FAE5" stroke="#059669"/><line x1="228" y1="55" x2="242" y2="55" stroke="#059669" stroke-width="3"/><text x="235" y="95" text-anchor="middle" font-size="10" fill="#666">Comparten electrones</text><text x="80" y="110" text-anchor="middle" font-size="10" fill="#666">Transferencia de electrones</text></svg>`},{type:`text`,title:`Enlace Iónico`,content:`Ocurre cuando un átomo cede electrones a otro. Ejemplo: NaCl. El sodio cede un electrón al cloro, formando iones Na⁺ y Cl⁻ que se atraen.`},{type:`text`,title:`Enlace Covalente`,content:`Ocurre cuando dos átomos comparten pares de electrones. Ejemplo: H₂O. Cada hidrógeno comparte un electrón con el oxígeno.`},{type:`interactive`,title:`Identifica el Enlace`,question:`¿Qué tipo de enlace tiene el CO₂?`,options:[`Iónico`,`Covalente`,`Metálico`,`Puente de H`],correctIndex:1,explanation:`El CO₂ tiene enlaces covalentes dobles: O=C=O.`}]},{id:`estados-materia`,title:`Estados de la Materia`,category:`Química General`,duration:`7 min`,icon:`❄️`,description:`Explora los estados sólido, líquido, gaseoso y los cambios de fase.`,steps:[{type:`text`,title:`Los Cuatro Estados`,content:`Sólido: forma y volumen fijos. Líquido: volumen fijo, forma variable. Gas: volumen y forma variables. Plasma: gas ionizado a altas temperaturas.`},{type:`diagram`,title:`Cambios de Estado`,caption:`Fusión, vaporización, solidificación, condensación, sublimación`,svg:`<svg viewBox="0 0 280 160" class="w-full max-w-sm mx-auto"><rect x="10" y="10" width="70" height="50" rx="6" fill="#DBEAFE" stroke="#2563EB"/><text x="45" y="40" text-anchor="middle" font-size="12" font-weight="bold" fill="#1E40AF">SÓLIDO</text><rect x="100" y="10" width="70" height="50" rx="6" fill="#D1FAE5" stroke="#059669"/><text x="135" y="40" text-anchor="middle" font-size="12" font-weight="bold" fill="#065F46">LÍQUIDO</text><rect x="190" y="10" width="70" height="50" rx="6" fill="#FEF3C7" stroke="#D97706"/><text x="225" y="40" text-anchor="middle" font-size="12" font-weight="bold" fill="#92400E">GAS</text><text x="45" y="85" text-anchor="middle" font-size="8" fill="#2563EB">Fusión →</text><text x="135" y="85" text-anchor="middle" font-size="8" fill="#059669">Vaporización →</text><text x="45" y="105" text-anchor="middle" font-size="8" fill="#2563EB">← Solidificación</text><text x="135" y="105" text-anchor="middle" font-size="8" fill="#059669">← Condensación</text><text x="90" y="130" text-anchor="middle" font-size="9" fill="#D97706">Sublimación (sólido ⇌ gas)</text></svg>`},{type:`example`,title:`Ejemplo Cotidiano`,content:`Agua hierve a 100°C (vaporización). Hielo se derrite a 0°C (fusión). Vapor se condensa en superficies frías (condensación).`},{type:`interactive`,title:`Cambio de Fase`,question:`¿Cómo se llama el cambio de líquido a gas?`,options:[`Fusión`,`Solidificación`,`Vaporización`,`Sublimación`],correctIndex:2,explanation:`La vaporización puede ser evaporación (lenta) o ebullición (rápida a 100°C).`}]},{id:`tabla-periodica`,title:`Tabla Periódica`,category:`Química General`,duration:`12 min`,icon:`📊`,description:`Domina la organización de elementos, períodos, grupos y tendencias.`,steps:[{type:`text`,title:`Organización`,content:`118 elementos ordenados por número atómico creciente. 7 períodos (filas) y 18 grupos (columnas). Elementos del mismo grupo tienen propiedades químicas similares.`},{type:`diagram`,title:`Bloques de la Tabla`,caption:`s, d, p, f — cada bloque corresponde a un orbital atómico`,svg:`<svg viewBox="0 0 300 90" class="w-full max-w-md mx-auto"><rect x="5" y="5" width="80" height="25" rx="4" fill="#DBEAFE" stroke="#2563EB"/><text x="45" y="21" text-anchor="middle" font-size="10" fill="#1E40AF">Bloque s</text><rect x="90" y="5" width="120" height="25" rx="4" fill="#FEE2E2" stroke="#DC2626"/><text x="150" y="21" text-anchor="middle" font-size="10" fill="#991B1B">Bloque d</text><rect x="215" y="5" width="80" height="25" rx="4" fill="#D1FAE5" stroke="#059669"/><text x="255" y="21" text-anchor="middle" font-size="10" fill="#065F46">Bloque p</text><rect x="90" y="40" width="120" height="25" rx="4" fill="#FEF3C7" stroke="#D97706"/><text x="150" y="56" text-anchor="middle" font-size="10" fill="#92400E">Bloque f (lantánidos/actínidos)</text></svg>`},{type:`text`,title:`Tendencias`,content:`Radio atómico: aumenta hacia abajo y la izquierda. Electronegatividad: aumenta hacia arriba y la derecha.`},{type:`interactive`,title:`Ubica el Elemento`,question:`¿En qué grupo está el Oxígeno (O)?`,options:[`Grupo 1`,`Grupo 14`,`Grupo 16`,`Grupo 18`],correctIndex:2,explanation:`El oxígeno está en el Grupo 16 (calcógenos). Tiene 6 electrones de valencia.`}]},{id:`reacciones-quimicas`,title:`Reacciones Químicas`,category:`Química General`,duration:`10 min`,icon:`⚡`,description:`Identifica y balancea reacciones químicas paso a paso.`,steps:[{type:`text`,title:`¿Qué es una Reacción Química?`,content:`Proceso donde unas sustancias (reactivos) se transforman en otras diferentes (productos) mediante reorganización de enlaces. Se representa con ecuaciones químicas.`},{type:`diagram`,title:`Partes de una Ecuación`,caption:`Reactivos → Productos. Coeficientes balancean la ecuación.`,svg:`<svg viewBox="0 0 320 60" class="w-full max-w-sm mx-auto"><text x="30" y="25" font-size="14" fill="#DC2626" font-weight="bold">CH₄</text><text x="80" y="25" font-size="14" fill="#666"> + </text><text x="110" y="25" font-size="14" fill="#2563EB" font-weight="bold">2 O₂</text><text x="175" y="25" font-size="18" fill="#666"> → </text><text x="210" y="25" font-size="14" fill="#059669" font-weight="bold">CO₂</text><text x="255" y="25" font-size="14" fill="#666"> + </text><text x="275" y="25" font-size="14" fill="#059669" font-weight="bold">2 H₂O</text><text x="160" y="50" text-anchor="middle" font-size="10" fill="#666">Reactivos → Productos</text></svg>`},{type:`text`,title:`Ley de Conservación`,content:`Lavoisier: "La materia no se crea ni se destruye". Número de átomos debe ser igual en reactivos y productos. Por eso balanceamos ecuaciones.`},{type:`example`,title:`Balanceo: N₂ + H₂ → NH₃`,content:`Ajustamos coeficientes: 1 N₂ + 3 H₂ → 2 NH₃. Verificamos: 2N, 6H → 2N, 6H. ¡Balanceado!`},{type:`interactive`,title:`Balancea la Ecuación`,question:`¿Cuántas moléculas de H₂O se producen al balancear H₂ + O₂ → H₂O?`,options:[`1 H₂O`,`2 H₂O`,`3 H₂O`,`4 H₂O`],correctIndex:1,explanation:`2 H₂ + O₂ → 2 H₂O. Se necesitan 2 H₂O para balancear 4H y 2O.`}]},{id:`ph-escalas`,title:`pH y Escalas de Acidez`,category:`Química General`,duration:`8 min`,icon:`🧪`,description:`Entiende la escala de pH, ácidos, bases y cómo medir la acidez.`,steps:[{type:`text`,title:`¿Qué es el pH?`,content:`El pH mide la concentración de iones H⁺. Escala 0-14: pH < 7 ácido, pH = 7 neutro, pH > 7 básico.`},{type:`diagram`,title:`Escala de pH`,caption:`Ejemplos cotidianos en la escala de pH`,svg:`<svg viewBox="0 0 300 120" class="w-full max-w-md mx-auto"><defs><linearGradient id="ph" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="#DC2626"/><stop offset="25%" stop-color="#F59E0B"/><stop offset="50%" stop-color="#10B981"/><stop offset="75%" stop-color="#3B82F6"/><stop offset="100%" stop-color="#8B5CF6"/></linearGradient></defs><rect x="10" y="10" width="280" height="20" rx="10" fill="url(#ph)"/><text x="45" y="50" font-size="10" fill="#DC2626">Ácido</text><text x="150" y="50" text-anchor="middle" font-size="10" fill="#10B981">Neutro</text><text x="255" y="50" text-anchor="middle" font-size="10" fill="#8B5CF6">Base</text><text x="20" y="75" font-size="9" fill="#DC2626">Limón pH 2</text><text x="150" y="75" text-anchor="middle" font-size="9" fill="#10B981">Agua pH 7</text><text x="230" y="75" font-size="9" fill="#3B82F6">Mar pH 8</text><text x="230" y="95" font-size="9" fill="#8B5CF6">Amoníaco pH 11</text></svg>`},{type:`text`,title:`Ácidos y Bases`,content:`Ácido: dona H⁺. Base: acepta H⁺. pH = -log[H⁺]. A menor pH, mayor acidez.`},{type:`interactive`,title:`Identifica el pH`,question:`Una sustancia con pH 3 es:`,options:[`Muy ácida`,`Ligeramente ácida`,`Neutra`,`Básica`],correctIndex:0,explanation:`pH 3 es muy ácido. El jugo de limón tiene pH ~2, el vinagre pH ~3.`}]}];export{e as t};